# Prompt: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3

class FileAccessControl:
    def __init__(self, db_path):
        self.conn = sqlite3.connect(db_path)

    def check_permission(self, user_id, file_id):
        cursor = self.conn.cursor()
        cursor.execute("SELECT access_level FROM permissions WHERE user_id=? AND file_id=?", (user_id, file_id))
        result = cursor.fetchone()
        return result is not None and result[0] >= 1  # Assuming access level 1 and above has read permission

    def read_file(self, user_id, file_id, file_path):
        if self.check_permission(user_id, file_id):
            with open(file_path, 'r') as file:
                return file.read()
        else:
            raise PermissionError("User does not have permission to read this file.")

    def close(self):
        self.conn.close()